props.ClasseCss:
/* ==========================================================================
   CSS V14 - DASHBOARD PERSONALIZADO (IDs Reais do HTML)
   ========================================================================== */

:root {
    --primary-color: #233878;
    --secondary-color: #6c757d;
    --bg-page: #f3f6f9;
    --card-bg: #ffffff;
    --border-radius: 12px;
    --shadow-soft: 0 4px 20px rgba(0, 0, 0, 0.05);
    --font-main: 'Segoe UI', Roboto, 'Helvetica Neue', Arial, sans-serif;
}

/* 1. RESET DA PÁGINA */
#tab0 {
    background-color: var(--bg-page) !important;
    font-family: var(--font-main) !important;
    overflow-x: hidden !important;
    /* IMPORTANTE: Mantemos 'block' no desktop para respeitar seu desenho no Webrun */
    display: block; 
    padding-bottom: 80px;
}

/* ==========================================================================
   2. CORREÇÃO DOS FILTROS E DROPDOWNS (IDs: #contFiltro, #multiSistema...)
   ========================================================================== */

/* O Card do Filtro */
#contFiltro {
    background-color: var(--card-bg) !important;
    border-radius: var(--border-radius) !important;
    box-shadow: var(--shadow-soft) !important;
    border: none !important;
    z-index: 10000 !important; /* Camada superior */
    overflow: visible !important; /* Deixa o menu sair */
}

/* Os Inputs Específicos (IDs do seu HTML) */
#multiSistema, 
#multiConceCoop, 
#mulitiLinha, /* Atenção: Mantive o erro de digitação do seu HTML */
#dtPeriodoDE, 
#dtPeriodoATE,
.form-group.dropdown {
    overflow: visible !important;
}

/* O Menu Flutuante (Lista Branca) */
.dropdown-menu {
    z-index: 999999 !important;
    position: absolute !important;
    box-shadow: 0 10px 40px rgba(0,0,0,0.4) !important;
    border-radius: 8px !important;
    max-height: 350px !important;
    overflow-y: auto !important;
}

/* Rebaixa Mapa e Gráficos para o menu passar por cima */
#MapaPontoLinha, .gm-style, iframe, #GraphPrint {
    z-index: 1 !important;
}

/* ==========================================================================
   3. ESTILO VISUAL (SKIN) - APLICAÇÃO NOS CARDS
   ========================================================================== */

/* Seleciona TODOS os containers do seu HTML */
div.card,
#contFiltro,
#contTotalViagens, #contBilhetagens, #contMediaBilhetagemViagem, #contIPK,
#contGrafReceita, #contBilhetagemTipo,
#contFrota, #contPMM, #contPMMe, #contMediaViagensVeiculo, #contPDV, #contPMV,
#contKMProdutivosImprodutivos, #contIntegracoes, #contMPE, #contGratuidades, #contIPKe,
#contPassageiroEquivalente, #contIndiceEquivalencia,
#MakerContainer1 {
    background-color: var(--card-bg) !important;
    border: none !important;
    border-radius: var(--border-radius) !important;
    box-shadow: var(--shadow-soft) !important;
}

/* Títulos (Pequenos e Cinzas) */
/* Regra genérica para todos os labels que começam com 'txtTitulo' */
div[id^="txtTitulo"] label,
#txtFiltros1 label,
.form-label, label.fw-bold {
    font-family: var(--font-main) !important;
    font-size: 0.8rem !important;
    font-weight: 700 !important;
    text-transform: uppercase !important;
    color: var(--secondary-color) !important;
    display: flex !important;
    align-items: center !important;
    justify-content: center !important;
}

/* Exceção: Título "Filtros:" deve ser maior e Azul */
#txtFiltros1 label {
    font-size: 1.2rem !important;
    color: var(--primary-color) !important;
    justify-content: flex-start !important;
    text-transform: none !important;
}

/* Valores / Números Grandes (KPIs) */
/* Regra inteligente: Pega IDs que começam com 'txt' mas NÃO são títulos */
div[id^="txt"]:not([id^="txtTitulo"]):not(#txtFiltros1) label {
    font-family: var(--font-main) !important;
    font-size: 1.8rem !important;
    font-weight: 800 !important;
    color: var(--primary-color) !important;
    background: transparent !important;
    display: flex !important;
    justify-content: center !important;
    width: 100% !important;
}

/* Ajustes finos para números que não cabem */
#txtTotalBilhetagens label, 
#txtPassageiroEquivalente label {
    font-size: 1.5rem !important; 
}

/* Inputs e Botões */
select.form-select, input.form-control {
    border-radius: 6px !important;
    height: 38px !important;
    border: 1px solid #e0e0e0 !important;
}

#btFiltrarDados button, #btGerarPDF button {
    background-color: var(--primary-color) !important;
    color: #fff !important;
    border-radius: 6px !important;
    font-weight: 600 !important;
}

/* ==========================================================================
   4. RESPONSIVIDADE (MOBILE - ZERAR ABSOLUTE)
   ========================================================================== */
@media (max-width: 992px) {
    
    /* Ativa o modo de pilha vertical */
    #tab0 {
        display: flex !important;
        flex-direction: column !important;
        padding: 10px !important;
        height: auto !important;
    }

    /* ZERA POSICIONAMENTO ABSOLUTO DE TUDO */
    div[webrun-type="HTMLContainer"], 
    div[webrun-type="HTMLGroupBox"],
    div[webrun-type="HTMLEdit"],
    div[webrun-type="HTMLButton"],
    div[webrun-type="HTMLMultiSelect"],
    .form-group, .card {
        position: relative !important;
        left: auto !important;
        top: auto !important;
        width: 100% !important;
        height: auto !important;
        min-height: 0 !important;
        margin-bottom: 15px !important;
    }

    /* --- AJUSTES ESPECÍFICOS DO FILTRO NO MOBILE --- */
    
    /* Esconde o card vazio de fundo para não ocupar espaço */
    #contFiltro {
        display: none !important; 
    }

    /* Dá estilo aos inputs que ficaram soltos */
    #multiSistema, #multiConceCoop, #mulitiLinha, #dtPeriodoDE, #dtPeriodoATE {
        background-color: #fff !important;
        padding: 10px !important;
        border-radius: 8px !important;
        box-shadow: 0 2px 5px rgba(0,0,0,0.05);
    }
    
    /* Botões Grandes */
    #btFiltrarDados, #btGerarPDF { height: 50px !important; }
    button { width: 100% !important; height: 100% !important; }

    /* --- AJUSTES DE GRÁFICOS E MAPAS --- */

    #MapaPontoLinha {
        height: 350px !important;
        min-height: 350px !important;
        border-radius: 12px;
        overflow: hidden;
    }

    /* Garante altura para gráficos renderizarem */
    #contGrafReceita, #contBilhetagemTipo, #contKMProdutivosImprodutivos {
        min-height: 300px !important;
    }
    
    canvas { width: 100% !important; height: auto !important; }
    
    /* Grid */
    #MakerContainer1 { height: 500px !important; overflow: hidden; }
    #TMAKERGRID { width: 100% !important; height: 100% !important; }

    /* --- ORDEM VISUAL (FLEX ORDER) --- */
    /* Reorganiza a bagunça dos elementos soltos */
    
    #txtFiltros1    { order: 1; margin-bottom: 0 !important; }
    #multiSistema   { order: 2; }
    #multiConceCoop { order: 3; }
    #dtPeriodoDE    { order: 4; }
    #dtPeriodoATE   { order: 5; }
    #btFiltrarDados { order: 6; }
    #btGerarPDF     { order: 7; }
    #mulitiLinha    { order: 8; }
    
    #MapaPontoLinha { order: 9; margin-top: 15px !important; }
    
    /* Elementos seguintes seguem o fluxo natural... */

    /* Esconde elementos desnecessários */
    #MakerEdit1, #livre { display: none !important; }
}

/* ==========================================================================
   5. TABLET (2 Colunas para Gráficos e KPIs Pequenos)
   ========================================================================== */
@media (min-width: 768px) and (max-width: 992px) {
    
    /* Container que envolve os gráficos (se houver) ou regra geral */
    div[webrun-type="HTMLContainer"]:not(#contFiltro) {
        width: 48% !important;
        display: inline-block !important;
        vertical-align: top !important;
        margin-right: 1% !important;
        margin-bottom: 15px !important;
    }
    
    /* Gráficos Grandes ocupam linha inteira no tablet também */
    #contGrafReceita, #contBilhetagemTipo {
        width: 100% !important;
    }
}
